+        let config = DbPoolConfig {
+            database_url: format!("sqlite:///{}", db_path.display()),
+            ..Default::default()
+        };
+        let pool = DbPool::new(&config).expect("create pool");
+
+        let rt = RuntimeBuilder::current_thread()
