+            let now = crate::now_micros();
+            conn.execute_raw(&format!(
+                "INSERT INTO projects (id, slug, human_key, created_at) \
+                 VALUES (1, 'limit-proj', '/tmp/limit', {now})"
+            ))
+            .expect("insert project");
