+        let primary = dir.path().join("test.db");
+        std::fs::write(&primary, b"db").expect("write primary");
+
+        // Should not error when WAL doesn't exist.
+        quarantine_sidecar(&primary, "-wal", "20260218_120000_000").expect("quarantine noop");
